parameters.jsCode:
const c = $('Construir Nota Visita').first().json;
const mem = c.memoria || {};
const odoo = c.odoo || $('Unificar Contexto Odoo').first().json.odoo;
const msg = String(c.mensaje_usuario_original || c.mensaje_usuario || '').trim();

function num(v) {
  const n = parseFloat(v);
  return Number.isFinite(n) ? n : null;
}

function toOdooDatetime(v) {
  if (v == null || v === '') return undefined;
  let s = String(v).trim();
  if (!s) return undefined;
  s = s.replace(/Z$/i, '').replace('T', ' ');
  if (s.length >= 19) return s.substring(0, 19);
  const d = new Date(v);
  if (!Number.isNaN(d.getTime())) {
    return d.toISOString().replace('T', ' ').substring(0, 19);
  }
  return undefined;
}

function resolveLeadId() {
  const cand = [mem.lead_id, mem.leadId, c.lead_id];
  for (const x of cand) {
    const n = parseInt(x, 10);
    if (Number.isFinite(n)) return n;
  }
  try {
    const id = $('Leer Descripción Actual Lead').first().json?.result?.[0]?.id;
    const n = parseInt(id, 10);
    if (Number.isFinite(n)) return n;
  } catch (e) {}
  try {
    const id = $('Crear Oportunidad Odoo').first().json?.result;
    const n = parseInt(id, 10);
    if (Number.isFinite(n)) return n;
  } catch (e) {}
  return null;
}

const leadOdooId = resolveLeadId();
if (leadOdooId == null) {
  throw new Error(
    'Falta lead_id para vincular la visita al CRM (memoria Postgres o lectura Odoo).'
  );
}

const refName = ('Visita — ' + (mem.lead_name || 'CRM') + ' — ' + (c.fecha_bonita || '')).slice(0, 200);

const vals = {
  name: refName,
  lead_id: leadOdooId,
  mensaje_comercial: msg || '(Sin resumen)',
  comercial_nombre: mem.user_name || '—'
};

if (mem.user_id != null && mem.user_id !== '') {
  vals.telegram_user_id = String(mem.user_id);
}

const ela = num(mem.entrada_lat);
const elo = num(mem.entrada_lon);
if (ela != null) vals.entrada_lat = ela;
if (elo != null) vals.entrada_lon = elo;
const ea = toOdooDatetime(mem.entrada_at);
if (ea) vals.entrada_at = ea;

const sla = num(mem.salida_lat);
const slo = num(mem.salida_lon);
if (sla != null) vals.salida_lat = sla;
if (slo != null) vals.salida_lon = slo;
const sa = toOdooDatetime(mem.salida_at);
if (sa) vals.salida_at = sa;

return {
  chat_id: c.chat_id,
  telegram_chat_id: c.telegram_chat_id,
  odoo,
  visita_payload: vals
};

