parameters.jsCode:
// Combinar datos de transcripción para que lleguen correctamente al AI Agent
const datosTranscripcion = $('Procesar Transcripción').item.json;
const datosOriginales = $('Detectar Tipo Inicial').first().json;

console.log('🔄 Combinando datos para AI Agent:');
console.log('📄 Datos originales:', JSON.stringify(datosOriginales, null, 2));
console.log('🎤 Datos transcripción:', JSON.stringify(datosTranscripcion, null, 2));

const plataforma = String(
  datosTranscripcion.plataforma ||
  datosOriginales.plataforma ||
  'telegram'
).toLowerCase().trim();

const canalEnvio = plataforma;

const chatId = datosTranscripcion.chat_id ?? datosOriginales.chat_id ?? null;
const userId = datosTranscripcion.user_id ?? datosOriginales.user_id ?? null;
const userName = datosTranscripcion.user_name ?? datosOriginales.user_name ?? 'Usuario';
const timestamp = datosTranscripcion.timestamp ?? datosOriginales.timestamp ?? new Date().toISOString();

const rawTelegramChatId =
  datosTranscripcion.telegram_chat_id ??
  datosOriginales.telegram_chat_id ??
  (plataforma === 'telegram' ? chatId : null);

const rawWhatsappPhone =
  datosTranscripcion.whatsapp_phone ??
  datosOriginales.whatsapp_phone ??
  (plataforma === 'whatsapp' ? chatId : null);

const telegramChatId =
  plataforma === 'telegram' &&
  rawTelegramChatId != null &&
  String(rawTelegramChatId).trim() !== ''
    ? Number(rawTelegramChatId)
    : null;

const whatsappPhone =
  plataforma === 'whatsapp' &&
  rawWhatsappPhone != null &&
  String(rawWhatsappPhone).trim() !== ''
    ? String(rawWhatsappPhone).replace(/\D/g, '').trim()
    : null;

const datosFinales = {
  ...datosOriginales,
  ...datosTranscripcion,

  chat_id: chatId,
  user_id: userId,
  user_name: userName,
  timestamp,

  plataforma,
  canal_respuesta: canalEnvio,
  canal_envio: canalEnvio,
  telegram_chat_id: telegramChatId,
  whatsapp_phone: whatsappPhone,

  es_audio: true,
  audio_transcrito: true,
  file_id: datosTranscripcion.file_id || datosOriginales.file_id
};

console.log('✅ Datos finales para AI Agent:', JSON.stringify(datosFinales, null, 2));
console.log('💬 Mensaje que recibirá AI Agent:', datosFinales.mensaje_usuario);

return datosFinales;

// Procesar transcripción de AssemblyAI y combinar con datos originales
const datosOriginales = $('Detectar Tipo Inicial').first().json;

console.log('📄 Respuesta completa de AssemblyAI:', JSON.stringify($json, null, 2));

// Canal/plataforma
const plataforma = String(datosOriginales.plataforma || 'telegram').toLowerCase().trim();
const canalEnvio = plataforma;

// IDs por canal
const rawChatId = datosOriginales.chat_id ?? null;
const rawTelegramChatId = datosOriginales.telegram_chat_id ?? rawChatId;
const rawWhatsappPhone = datosOriginales.whatsapp_phone ?? rawChatId;

const telegramChatId =
  plataforma === 'telegram' &&
  rawTelegramChatId != null &&
  String(rawTelegramChatId).trim() !== ''
    ? Number(rawTelegramChatId)
    : null;

const whatsappPhone =
  plataforma === 'whatsapp' &&
  rawWhatsappPhone != null &&
  String(rawWhatsappPhone).trim() !== ''
    ? String(rawWhatsappPhone).replace(/\D/g, '').trim()
    : null;

// AssemblyAI devuelve la transcripción en el campo 'text'
let transcripcion = '';

if ($json.status === 'completed' && $json.text) {
  transcripcion = $json.text;
} else if ($json.status === 'error') {
  transcripcion = '[Error en transcripción: ' + ($json.error || 'Error desconocido') + ']';
  console.error('❌ Error en AssemblyAI:', $json.error);
} else if ($json.status === 'processing') {
  transcripcion = '[Transcripción aún en proceso, espera un momento más]';
  console.log('⏳ AssemblyAI aún está procesando');
} else if ($json.status === 'queued') {
  transcripcion = '[Transcripción en cola, espera un momento]';
  console.log('⏳ AssemblyAI en cola');
} else {
  transcripcion = $json.text || $json.transcript || '[Error: no se pudo obtener transcripción]';
}

transcripcion = String(transcripcion).trim();

if (!transcripcion || transcripcion === '' || transcripcion === 'undefined') {
  transcripcion = '[Error: transcripción vacía]';
  console.error('❌ Error: No se pudo obtener transcripción válida');
  console.error('📄 Estado:', $json.status);
  console.error('📄 Datos recibidos:', JSON.stringify($json, null, 2));
}

console.log('🎤 Transcripción obtenida de AssemblyAI (ES):', transcripcion);
console.log('📊 Estado AssemblyAI:', $json.status);
console.log('🌍 Idioma detectado:', $json.language_code);
console.log('🎯 Confianza:', $json.confidence);

// Versión normalizada
const transcripcionNormalizada = transcripcion
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/´/g, '')
  .toLowerCase();

console.log('🎤 Transcripción normalizada (sin tildes):', transcripcionNormalizada);

return {
  ...datosOriginales,

  // canal
  plataforma,
  canal_respuesta: canalEnvio,
  canal_envio: canalEnvio,
  telegram_chat_id: telegramChatId,
  whatsapp_phone: whatsappPhone,

  // mensaje
  mensaje_usuario: transcripcionNormalizada,
  transcripcion_original: transcripcion,
  mensaje_usuario_original: transcripcion,

  es_audio: true,
  audio_transcrito: true,
  assemblyai_response: $json,
  transcriptor: 'assemblyai',
  estado_transcripcion: $json.status,
  confidence: $json.confidence,
  audio_duration: $json.audio_duration
};

const datosArchivo = $json;
const datosOriginales = $('Detectar Tipo Inicial').first().json;

const plataforma = String(datosOriginales.plataforma || 'telegram').toLowerCase().trim();

let fileId = datosOriginales.file_id || null;
let filePath = null;
let mediaUrl = null;
let mimeType = null;

if (plataforma === 'telegram') {
  if (datosArchivo.file_path) {
    filePath = datosArchivo.file_path;
  } else if (datosArchivo.result?.file_path) {
    filePath = datosArchivo.result.file_path;
  } else if (datosArchivo.body?.result?.file_path) {
    filePath = datosArchivo.body.result.file_path;
  }

  if (!fileId) {
    throw new Error('No se obtuvo file_id de Telegram');
  }

  return {
    ...datosOriginales,
    ...datosArchivo,
    plataforma,
    canal_envio: 'telegram',
    file_id: fileId,
    file_path: filePath,
    media_url: null,
    mime_type: datosArchivo.mime_type || null,
    voice_file_ready: true,
    processing_method: 'telegram_get_file',
    download_info: {
      file_id: fileId,
      file_path: filePath,
      method: 'telegram_get_file',
    },
  };
}

if (plataforma === 'whatsapp') {
  fileId = datosArchivo.id || datosOriginales.file_id || null;
  mediaUrl = datosArchivo.url || datosArchivo.body?.url || null;
  mimeType = datosArchivo.mime_type || datosArchivo.body?.mime_type || null;

  if (!mediaUrl) {
    throw new Error('No se obtuvo media_url de WhatsApp');
  }

  return {
    ...datosOriginales,
    ...datosArchivo,
    plataforma,
    canal_envio: 'whatsapp',
    file_id: fileId,
    file_path: null,
    media_url: mediaUrl,
    mime_type: mimeType,
    voice_file_ready: true,
    processing_method: 'whatsapp_media_url',
    download_info: {
      file_id: fileId,
      file_path: null,
      media_url: mediaUrl,
      method: 'whatsapp_media_download',
    },
  };
}

throw new Error(`Plataforma no soportada: ${plataforma}`);

const msg = $json.message || {};

let tipo_mensaje = 'unknown';
if (msg.location) tipo_mensaje = 'location';
else if (msg.voice) tipo_mensaje = 'voice';
else if (msg.text) tipo_mensaje = 'text';

return {
  raw_message: msg,
  chat_id: msg.chat?.id || null,
  telegram_chat_id: msg.chat?.id || null,
  user_id: msg.from?.id || null,
  user_name: [msg.from?.first_name, msg.from?.last_name].filter(Boolean).join(' ').trim(),
  tipo_mensaje,
  mensaje_usuario: msg.text || '',
  mensaje_usuario_original: msg.text || '',
  latitude: msg.location?.latitude || null,
  longitude: msg.location?.longitude || null,
  file_id: msg.voice?.file_id || null,
  fecha_hora: new Date().toISOString(),
  plataforma: 'telegram',
  es_audio: tipo_mensaje === 'voice'
};

const textoOriginal = String($json.mensaje_usuario_original || $json.mensaje_usuario || '').trim();

const textoNormalizado = textoOriginal
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .trim();

return {
  ...$json,
  mensaje_usuario: textoNormalizado,
  mensaje_usuario_original: textoOriginal,
  es_audio: false
};

const actual = $('Router Principal CRM').first().json;
const auth = $('Autenticar Odoo').first().json;

const uid = auth.result;

if (!uid) {
  throw new Error('No se obtuvo uid de Odoo en la autenticación');
}

return {
  ...actual,
  odoo: {
    url: 'https://lsanchezgoshawk-crm.odoo.com/jsonrpc',
    db: 'lsanchezgoshawk-crm-main-31347967',
    username: 'admin',
    password: 'admin',
    uid
  }
};

const texto = String($json.mensaje_usuario_original || $json.mensaje_usuario || '').trim();

function trimVal(s) {
  return String(s || '').replace(/^[\s:\-–—]+|[\s:\-–—]+$/g, '').trim();
}

function matchLabel(segment, regex) {
  const m = segment.match(regex);
  return m ? trimVal(m[1]) : '';
}

let nombreCliente = '';
let contacto = '';
let empresa = '';
let street = '';

const segmentos = texto
  .split(/[,;\n]+/)
  .map((s) => s.trim())
  .filter(Boolean);

for (const p of segmentos) {
  let v = matchLabel(p, /^(?:nombre\s+del\s+)?cliente\s*[:\-–—]?\s*(.+)$/i);
  if (v) {
    nombreCliente = v;
    continue;
  }
  v = matchLabel(p, /^el\s+cliente\s+(?:es|llama)\s+(.+)$/i);
  if (v) {
    nombreCliente = v;
    continue;
  }
  v = matchLabel(p, /^contacto(?:\s+principal)?\s*[:\-–—]?\s*(.+)$/i);
  if (v) {
    contacto = v;
    continue;
  }
  v = matchLabel(p, /^persona\s+de\s+contacto\s*[:\-–—]?\s*(.+)$/i);
  if (v) {
    contacto = v;
    continue;
  }
  v = matchLabel(p, /^empresa\s*[:\-–—]?\s*(.+)$/i);
  if (v) {
    empresa = v;
    continue;
  }
  v = matchLabel(p, /^(?:compa[ñn]ia|compañía|raz[oó]n\s+social)\s*[:\-–—]?\s*(.+)$/i);
  if (v) {
    empresa = v;
    continue;
  }
  v = matchLabel(p, /^(?:calle|direcci[oó]n|domicilio|street)\s*[:\-–—]?\s*(.+)$/i);
  if (v) {
    street = v;
    continue;
  }
}

if (!nombreCliente) {
  const mFull = texto.match(
    /(?:^|[\s,;])(?:nombre\s+del\s+)?cliente\s*[:\-–—]\s*([^\n,;]+?)(?=[\n,;]|$)/i
  );
  if (mFull) nombreCliente = trimVal(mFull[1]);
}
if (!contacto) {
  const m = texto.match(/(?:^|[\s,;])contacto\s*[:\-–—]\s*([^\n,;]+?)(?=[\n,;]|$)/i);
  if (m) contacto = trimVal(m[1]);
}
if (!empresa) {
  const m = texto.match(/(?:^|[\s,;])empresa\s*[:\-–—]\s*([^\n,;]+?)(?=[\n,;]|$)/i);
  if (m) empresa = trimVal(m[1]);
}
if (!street) {
  const m = texto.match(
    /(?:^|[\s,;])(?:calle|direcci[oó]n|domicilio)\s*[:\-–—]\s*([^\n,;]+?)(?=[\n,;]|$)/i
  );
  if (m) street = trimVal(m[1]);
}

if (!nombreCliente && segmentos.length > 0) {
  const primero = segmentos[0];
  const low = primero.toLowerCase();
  const esEtiqueta =
    /^(?:cliente|contacto|empresa|calle|direcci|domicilio|necesidad|presupuesto|urgencia|nombre\s+del)/i.test(
      low
    );
  if (!esEtiqueta && primero.length <= 120) {
    nombreCliente = trimVal(primero);
  }
}

nombreCliente = trimVal(nombreCliente);
contacto = trimVal(contacto);
empresa = trimVal(empresa);
street = trimVal(street);

if (
  contacto &&
  nombreCliente &&
  contacto.toLowerCase() === nombreCliente.toLowerCase()
) {
  contacto = '';
}

const tituloNombre =
  nombreCliente || contacto || empresa || 'Telegram';

const tieneAlgunaPista =
  Boolean(nombreCliente) ||
  Boolean(contacto) ||
  Boolean(empresa) ||
  Boolean(street) ||
  texto.replace(/\s+/g, ' ').length > 6;

const puede_crear_oportunidad = tieneAlgunaPista;

if (!puede_crear_oportunidad) {
  return {
    ...$json,
    puede_crear_oportunidad: false,
    opportunity_payload: null,
    partner_busqueda: null,
    mensaje_falta_cliente:
      'No he podido extraer datos. Escribe al menos **contacto**, **empresa**, **cliente**, **dirección** o un resumen concreto (por ejemplo: *Contacto: …, Empresa: …*).'
  };
}

const partner_busqueda =
  (empresa || nombreCliente || contacto || '').trim() || null;

const opportunity_payload = {
  name: `Oportunidad ${tituloNombre}`,
  type: 'opportunity',
  description: texto
};

if (empresa) opportunity_payload.partner_name = empresa;
if (street) opportunity_payload.street = street;
if (contacto) opportunity_payload.contact_name = contacto;
else if (nombreCliente) opportunity_payload.contact_name = nombreCliente;

return {
  ...$json,
  puede_crear_oportunidad: true,
  partner_busqueda,
  opportunity_payload,
  opportunity_datos_parseados: {
    nombre_cliente: nombreCliente || undefined,
    contact_name: contacto || undefined,
    partner_name: empresa || undefined,
    street: street || undefined
  }
};

