const prep = $('Preparar Payload Nueva Oportunidad').first().json;
const raw = $json;

let partners = [];
if (raw && Array.isArray(raw.result)) {
  partners = raw.result;
}

const d = prep.opportunity_datos_parseados || {};
const nombreCliente = String(d.nombre_cliente || '').trim();
const contacto = String(d.contact_name || '').trim();
const empresa = String(d.partner_name || '').trim();
const street = String(d.street || '').trim();

// Buscar el "cliente" en res.partner si el usuario lo ha indicado.
// Si no viene, caemos al valor previo calculado en el paso de preparación.
const partner_busqueda = String(nombreCliente || prep.partner_busqueda || '').trim();
let partner_id = null;

const payload = { ...(prep.opportunity_payload || {}) };

function norm(s) {
  return String(s || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

// Resolver partner_id: si hay varios resultados, usar coincidencia exacta por nombre.
if (partner_busqueda) {
  const target = norm(partner_busqueda);
  const exact = partners.find((p) => norm(p && p.name) === target);
  if (exact && exact.id) {
    partner_id = exact.id;
  } else if (partners.length === 1) {
    partner_id = partners[0].id;
  }
}

if (partner_id) {
  payload.partner_id = partner_id;
  if (contacto) payload.contact_name = contacto;
  else if (nombreCliente) payload.contact_name = nombreCliente;
  else if (partner_busqueda) payload.contact_name = partner_busqueda;
  if (empresa) payload.partner_name = empresa;
  if (street) payload.street = street;
} else {
  if (empresa) payload.partner_name = empresa;
  if (street) payload.street = street;

  // Si no encontramos el cliente en res.partner, el nombre debe ir a "Nombre del contacto".
  // Evitamos que la empresa acabe como fallback en contact_name.
  const busquedaSirveComoContacto =
    partner_busqueda && norm(partner_busqueda) !== norm(empresa);

  const cn =
    contacto ||
    nombreCliente ||
    (busquedaSirveComoContacto ? partner_busqueda : '') ||
    '';

  if (cn) payload.contact_name = cn;
}

return {
  ...prep,
  odoo: prep.odoo,
  opportunity_payload: payload,
  res_partner_candidatos: partners,
  partner_id_resuelto: partner_id
};

