const prep = $('Preparar Registro Visita Odoo').first().json;
let res = $json;
if (res.body && typeof res.body === 'object' && (res.body.result !== undefined || res.body.error)) {
  res = res.body;
}
if (res.data && typeof res.data === 'object' && (res.data.result !== undefined || res.data.error)) {
  res = res.data;
}

if (res.error) {
  const det =
    res.error.data?.message ||
    res.error.data?.debug ||
    res.error.message ||
    JSON.stringify(res.error);
  throw new Error('Odoo no creó la visita: ' + det);
}

if (res.result === undefined || res.result === false) {
  throw new Error(
    'Odoo no devolvió id de visita. Respuesta: ' + JSON.stringify(res).slice(0, 2000)
  );
}

return {
  ...prep,
  chat_id: prep.chat_id,
  visita_odoo_id: res.result
};
